update public.native_indicator_definitions set calculation_config=jsonb_build_object('metric',jsonb_build_object('table','operation_records','field','gross_weight','aggregation','sum'),'dimension',jsonb_build_object('table','operation_records','field','destination_state'),'limit',50) where indicator_key='weight_by_destination_state';
update public.native_indicator_definitions set calculation_config=jsonb_build_object('metric',jsonb_build_object('table','operation_records','field','volume_count','aggregation','sum'),'dimension',jsonb_build_object('table','operation_records','field','customer_name'),'limit',50) where indicator_key='transport_volumes_by_customer';
update public.native_indicator_definitions set calculation_config=jsonb_build_object('metric',jsonb_build_object('table','operation_records','field','id','aggregation','count'),'dimension',jsonb_build_object('table','operation_records','field','driver_name'),'limit',50) where indicator_key='transport_deliveries_by_driver';
update public.native_indicator_definitions set calculation_config=jsonb_build_object('metric',jsonb_build_object('table','operation_records','field','id','aggregation','count'),'dimension',jsonb_build_object('table','operation_records','field','vehicle_plate'),'limit',50) where indicator_key='transport_deliveries_by_vehicle';
update public.native_indicator_definitions set calculation_config=jsonb_build_object('metric',jsonb_build_object('table','operation_records','field','id','aggregation','count'),'dimension',jsonb_build_object('table','transport_records','field','route_name'),'limit',50) where indicator_key='transport_deliveries_by_route';
update public.native_indicator_definitions set calculation_config=jsonb_build_object('metric',jsonb_build_object('table','operation_records','field','id','aggregation','count'),'dimension',jsonb_build_object('table','transport_records','field','vehicle_type'),'limit',50) where indicator_key='transport_deliveries_by_vehicle_type';
update public.native_indicator_definitions set calculation_config=jsonb_build_object('metric',jsonb_build_object('table','operation_records','field','gross_weight','aggregation','sum'),'dimension',jsonb_build_object('table','transport_records','field','route_name'),'limit',50) where indicator_key='transport_weight_by_route';

update public.native_indicator_definitions set calculation_config='{"denominator":{"filter":[{"table":"operation_records","field":"completed_at","operator":"not_null"},{"table":"operation_records","field":"expected_date","operator":"not_null"}]},"numerator":{"filter":[{"table":"operation_records","field":"completed_at","operator":"lte_field","compare_field":"expected_date"}]}}'::jsonb where indicator_key='transport_otd';
update public.native_indicator_definitions set calculation_config='{"date_pairs":[{"start":{"table":"operation_records","field":"issued_at"},"end":{"table":"operation_records","field":"completed_at"}},{"start":{"table":"operation_records","field":"issued_at"},"end":{"table":"transport_records","field":"delivered_at"}},{"start":{"table":"transport_records","field":"collected_at"},"end":{"table":"transport_records","field":"delivered_at"}}],"unit":"hours"}'::jsonb where indicator_key in ('transport_average_delivery_time','transport_avg_delivery_time');
update public.native_indicator_definitions set calculation_config='{"date_pairs":[{"start":{"table":"operation_records","field":"expected_date"},"end":{"table":"operation_records","field":"completed_at"}},{"start":{"table":"operation_records","field":"expected_date"},"end":{"table":"transport_records","field":"delivered_at"}}],"unit":"hours"}'::jsonb where indicator_key in ('transport_average_delay','transport_avg_delay');
update public.native_indicator_definitions set calculation_config='{"denominator":{"filter":[{"table":"transport_records","field":"sla_status","operator":"not_null"}]},"numerator":{"filter":[{"table":"transport_records","field":"sla_status","operator":"in","value":["met","on_time","cumprido","cumprida","ok"]}]}}'::jsonb where indicator_key='transport_sla_compliance';
